const raw = $json;
const ocrText =
  raw.text ||
  raw.content ||
  raw.extractedText ||
  raw.output ||
  (Array.isArray(raw.pages) ? raw.pages.map(p => p.markdown || p.text || '').join('\n\n') : '') ||
  JSON.stringify(raw, null, 2);

return {
  json: {
    ocr_text: ocrText,
    ocr_raw: raw,
    received_at: new Date().toISOString()
  }
};

