const content = $json.choices?.[0]?.message?.content;
let data;

try {
  data = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  data = {
    document_type: "unknown",
    invoice_number: null,
    invoice_date: null,
    supplier_name: null,
    currency: null,
    total_amount: null,
    line_items: [],
    confidence: 0,
    parse_error: "Model output was not valid JSON"
  };
}

function toNumber(value) {
  if (value === null || value === undefined || value === "") return null;
  if (typeof value === "number") return value;
  const cleaned = String(value).replace(/[^0-9.-]/g, "");
  const num = Number(cleaned);
  return Number.isNaN(num) ? null : num;
}

function normalizeDate(value) {
  if (!value) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value;

  const m1 = String(value).match(/^(\d{1,2})[-\/ ]([A-Za-z]{3,9})[-\/ ](\d{4})$/);
  if (m1) {
    const months = {
      jan:"01", january:"01", feb:"02", february:"02", mar:"03", march:"03",
      apr:"04", april:"04", may:"05", jun:"06", june:"06", jul:"07", july:"07",
      aug:"08", august:"08", sep:"09", sept:"09", september:"09", oct:"10", october:"10",
      nov:"11", november:"11", dec:"12", december:"12"
    };
    const day = m1[1].padStart(2, "0");
    const mon = months[m1[2].toLowerCase()];
    const year = m1[3];
    if (mon) return `${year}-${mon}-${day}`;
  }

  const m2 = String(value).match(/^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/);
  if (m2) {
    return `${m2[3]}-${m2[2].padStart(2, "0")}-${m2[1].padStart(2, "0")}`;
  }

  return value;
}

data.total_amount = toNumber(data.total_amount);
data.invoice_date = normalizeDate(data.invoice_date);

if (!Array.isArray(data.line_items)) data.line_items = [];
if (typeof data.confidence !== "number") {
  const c = Number(data.confidence);
  data.confidence = Number.isNaN(c) ? 0 : c;
}

return {
  json: data
};
